import { Component, OnInit, AfterViewInit } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { ActivatedRoute, Router } from '@angular/router';
import { CartService } from '../services/cart.service';
import { AuthService } from '../services/auth.service';
import { ToastService } from '../services/toast.service';
import { Product } from '../models/models';

@Component({
  selector: 'app-home',
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.css']
})
export class HomeComponent implements OnInit, AfterViewInit {
  products: Product[] = [];
  filteredProducts: Product[] = [];
  loading = true;
  error = '';
  selectedCategory = 'All';
  searchQuery = '';
  highlightedProductId: number | null = null;

  constructor(
    private http: HttpClient,
    private cartService: CartService,
    private authService: AuthService,
    private toastService: ToastService,
    private router: Router,
    private route: ActivatedRoute
  ) {}

  ngOnInit() {
    this.loadProducts();
    
    // Subscribe to query params changes
    this.route.queryParams.subscribe(params => {
      this.searchQuery = params['search'] || '';
      if (this.products.length > 0) {
        this.applyFilters();
      }
    });
  }

  ngAfterViewInit() {
    setTimeout(() => this.highlightSearchedProduct(), 500);
  }

  loadProducts() {
    this.loading = true;
    this.http.get<Product[]>('http://localhost:3000/api/products')
      .subscribe({
        next: (data) => {
          this.products = data;
          this.fetchProductImages();
          this.applyFilters(); // Apply filters after products are loaded
          this.loading = false;
        },
        error: (error) => {
          this.error = 'Failed to load products';
          this.loading = false;
          this.toastService.showError('Failed to load products');
        }
      });
  }

  fetchProductImages() {
    // Use picsum for placeholder images (free, no API key)
    this.products.forEach((p, index) => {
      if (!p.image_url || p.image_url === '') {
        p.image_url = `https://picsum.photos/200/200?random=${index + 1}`;
      }
    });
  }

  filterByCategory(category: string) {
    this.selectedCategory = category;
    this.applyFilters();
    
    // Clear search query from URL when changing category
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { search: null },
      queryParamsHandling: 'merge'
    });
  }

  applyFilters() {
    // Start with all products
    let filtered = [...this.products];
    
    // Apply category filter
    if (this.selectedCategory !== 'All') {
      filtered = filtered.filter(p => p.category === this.selectedCategory);
    }
    
    // Apply search filter if exists
    if (this.searchQuery && this.searchQuery.trim() !== '') {
      const query = this.searchQuery.toLowerCase();
      filtered = filtered.filter(p =>
        p.name.toLowerCase().includes(query) ||
        p.description.toLowerCase().includes(query) ||
        p.category.toLowerCase().includes(query)
      );
      
      // Highlight first matching product
      if (filtered.length > 0) {
        this.highlightedProductId = filtered[0].id;
      } else {
        this.highlightedProductId = null;
      }
    } else {
      // No search query, clear highlight
      this.highlightedProductId = null;
    }
    
    this.filteredProducts = filtered;
  }

  clearSearch() {
    this.searchQuery = '';
    this.highlightedProductId = null;
    
    // Remove search param from URL
    this.router.navigate([], {
      relativeTo: this.route,
      queryParams: { search: null },
      queryParamsHandling: 'merge'
    });
    
    this.applyFilters();
  }

  highlightSearchedProduct() {
    if (this.highlightedProductId) {
      setTimeout(() => {
        const element = document.getElementById(`product-${this.highlightedProductId}`);
        if (element) {
          element.scrollIntoView({ behavior: 'smooth', block: 'center' });
          element.classList.add('highlight');
          setTimeout(() => element.classList.remove('highlight'), 3000);
        }
      }, 100);
    }
  }

  addToCart(product: Product) {
    if (!this.authService.isLoggedIn()) {
      this.toastService.showError('Please login to add items to cart');
      this.router.navigate(['/login']);
      return;
    }
    this.cartService.addToCart(product.id, 1).subscribe({
      next: () => {
        this.cartService.refreshCart();
        this.toastService.showSuccess(`${product.name} added to cart successfully!`);
      },
      error: (err: any) => {
        this.toastService.showError(err.error?.error || 'Failed to add to cart');
      }
    });
  }

  shopNow() {
    document.getElementById('products-section')?.scrollIntoView({ behavior: 'smooth' });
  }

  getCategoryIcon(category: string): string {
    const icons: { [key: string]: string } = {
      'Electronics': 'fas fa-laptop',
      'Fashion': 'fas fa-tshirt',
      'Home': 'fas fa-home',
      'Books': 'fas fa-book'
    };
    return icons[category] || 'fas fa-tag';
  }
}
